        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    """dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list면 복사본을, 아니면 빈 list를 반환합니다."""

    return deepcopy(value) if isinstance(value, list) else []


class UserFriendlyMarkdownOutput(Component):
    """Langflow 화면에 표시되는 05 커스텀 컴포넌트 클래스."""

    display_name = "05 사용자용 설계서 출력"
    description = "AI 에이전트 설계 결과를 플레이그라운드에서 보기 좋은 Markdown 설계서로 출력합니다."
    icon = "FileText"
    inputs = [DataInput(name="payload", display_name="AI 에이전트 설계 결과", required=True)]
    outputs = [Output(name="markdown_message", display_name="사용자용 설계서", method="build_message")]

    def build_message(self) -> Message:
        """사용자에게 보여줄 Markdown Message를 생성합니다."""

        text = build_agent_design_markdown(getattr(self, "payload", None))
        self.status = {"Markdown 글자 수": len(text)}
        return Message(text=text)

from __future__ import annotations

"""00 리포트 요청/데이터 불러오기 노드.

이 파일은 Langflow 체험용 첫 번째 노드입니다.
사용자가 입력한 질문, 보고 싶은 방식, CSV/JSON 텍스트, File Read 결과를 하나의
표준 payload로 정리해서 뒤 노드들이 같은 형식으로 처리할 수 있게 합니다.
"""

import csv
import io
import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


def build_demo_report_request(
    question: str,
    view_request: str = "",
    data_text: str = "",
    file_data: Any = None,
) -> dict[str, Any]:
    """질문과 입력 데이터를 HTML 리포트 flow의 표준 요청 payload로 만듭니다.

    `data_text`에 직접 붙여넣은 CSV/JSON이 있으면 그것을 우선 사용하고,
    비어 있으면 `file_data`에 연결된 File Read 결과에서 텍스트를 꺼냅니다.
    이후 CSV/JSON/JSONL 여부를 판단해 rows/columns 형태로 맞춰 둡니다.
    여러 dataset이 들어온 경우에는 공통 key를 찾아 자동으로 결합 view를 만들고,
    단일 CSV/rows 입력은 기존처럼 하나의 입력 데이터 view로 처리합니다.
    """

    text = _select_input_text(data_text, file_data)
    datasets = _parse_datasets(text)
    visual_request = _infer_visual_request(question, view_request)
    data_views, relationship_candidates, active_view = _build_data_views(datasets, str(question or ""), str(view_request or ""))
    rows = _rows(active_view.get("rows"))
    columns = _strings(active_view.get("columns")) or _columns_from_rows(rows)
    row_count = _positive_int(active_view.get("row_count"), len(rows))

    compact_datasets = []
    for item in datasets:
        # 뒤 노드에는 전체 rows를 여러 번 넘기지 않고, 데이터셋 목록에는 요약만 남깁니다.
        item_rows = _rows(item.get("rows"))
        item_columns = _strings(item.get("columns")) or _columns_from_rows(item_rows)
        compact_datasets.append(
            {
                "dataset_id": str(item.get("dataset_id") or ""),
                "label": str(item.get("label") or item.get("dataset_id") or ""),
                "columns": item_columns,
                "row_count": _positive_int(item.get("row_count"), len(item_rows)),
                "data_ref": _dict(item.get("data_ref")),
            }
        )

    compact_views = []
    for view in data_views:
        compact_views.append(
            {
                "data_view_id": str(view.get("data_view_id") or ""),
                "label": str(view.get("label") or view.get("data_view_id") or ""),
                "strategy": str(view.get("strategy") or "select"),
                "source_dataset_ids": _strings(view.get("source_dataset_ids")),
                "join_keys": _strings(view.get("join_keys")),
                "columns": _strings(view.get("columns")),
                "row_count": _positive_int(view.get("row_count"), len(_rows(view.get("rows")))),
            }
        )

    payload = {
        "payload_version": "html-report-demo-v1",
        "flow_type": "html_report_demo",
        "status": "ok",
        "request": {
            "question": str(question or ""),
            "view_request": str(view_request or ""),
            "selected_dataset_id": str(active_view.get("source_dataset_ids", [""])[0] if active_view.get("source_dataset_ids") else ""),
            "active_data_view_id": str(active_view.get("data_view_id") or ""),
            "visual_request": visual_request,
        },
        "available_datasets": compact_datasets,
        "available_data_views": compact_views,
        "data_views": data_views,
        "relationship_candidates": relationship_candidates,
        "api_response": {
            "status": "ok",
            "response_type": "demo_data",
            "message": "Demo data loaded for HTML report generation.",
            "data": {
                "data_view_id": str(active_view.get("data_view_id") or ""),
                "label": str(active_view.get("label") or ""),
                "strategy": str(active_view.get("strategy") or "select"),
                "source_dataset_ids": _strings(active_view.get("source_dataset_ids")),
                "join_keys": _strings(active_view.get("join_keys")),
                "columns": columns,
                "rows": rows,
                "row_count": row_count,
                "data_ref": _dict(active_view.get("data_ref")),
                "data_is_preview": row_count > len(rows),
            },
        },
        "warnings": [],
        "errors": [],
    }
    if not rows:
        payload["warnings"].append("No rows were loaded from data_text or file_data.")
    if len(datasets) > 1:
        payload["warnings"].append(
            f"Multiple datasets loaded; active data view is '{active_view.get('data_view_id')}' using strategy '{active_view.get('strategy')}'."
        )
    return payload


def _infer_visual_request(question: str, view_request: str) -> dict[str, Any]:
    """질문/표시 요구에 직접 드러난 키워드만 약한 힌트로 추출합니다.

    사람마다 작성 방식이 다르기 때문에 이 값은 최종 해석이 아닙니다.
    LLM은 원문 질문과 원문 표시 요구를 우선하고, 이 힌트는 fallback 초안에만 참고합니다.
    """

    raw_view_request = str(view_request or "").strip()
    text = " ".join(part for part in (str(question or ""), raw_view_request) if part).lower()
    requested_blocks: list[str] = []

    def add(block_id: str) -> None:
        if block_id not in requested_blocks:
            requested_blocks.append(block_id)

    if _contains(text, ["kpi", "card", "\uce74\ub4dc", "\uc9c0\ud45c", "\uc8fc\uc694\uac12", "\uc8fc\uc694 \uac12"]):
        add("kpi_card_grid")
    if _contains(text, ["\ucd94\uc774", "\uc2dc\uacc4\uc5f4", "\uc120\uadf8\ub798\ud504", "\ub77c\uc778", "trend", "line"]):
        add("trend_line_chart")
    if _contains(text, ["\ube44\uad50", "\ub9c9\ub300", "bar", "comparison", "\ud56d\ubaa9\ubcc4", "\uc720\ud615\ubcc4", "\ubb38\ud56d\ubcc4"]):
        add("comparison_bar_chart")
    if _contains(text, ["\ub3c4\ub11b", "\uc6d0\ud615", "\ud30c\uc774", "donut", "pie", "\ube44\uc911", "\uad6c\uc131\ube44", "\uc810\uc720\uc728"]):
        add("donut_chart")
    if _contains(text, ["\ubb36\uc74c", "\ub098\ub780\ud788", "\ubcf5\uc218 \uc9c0\ud45c", "grouped", "clustered"]):
        add("grouped_bar_chart")
    if _contains(text, ["\ub204\uc801", "stacked", "breakdown", "\uc0c1\ud0dc\ubcc4", "\uad6c\ubd84\ubcc4"]):
        add("stacked_comparison_bar")
    if _contains(text, ["\ud788\ud2b8\ub9f5", "\uad50\ucc28", "\uad50\ucc28\ud45c", "\ub9e4\ud2b8\ub9ad\uc2a4", "pivot", "matrix", "heatmap"]):
        add("heatmap_matrix")
    if _contains(text, ["\ubd84\ud3ec", "\ud3b8\ucc28", "\uc0b0\ud3ec", "histogram", "distribution"]):
        add("distribution_histogram")
    if _contains(text, ["\uc0c1\uad00", "\uc0b0\uc810\ub3c4", "scatter", "correlation", "relationship"]):
        add("scatter_plot")
    if _contains(text, ["\uc21c\uc704", "\ub7ad\ud0b9", "top", "bottom", "ranking"]):
        add("ranking_table")
    if _contains(text, ["\uc0c1\uc138", "\uc0c1\uc138\ud45c", "\ud45c", "\ud14c\uc774\ube14", "\ubaa9\ub85d", "\ub9ac\uc2a4\ud2b8", "detail", "table", "raw"]):
        add("detail_data_table")
    if _contains(text, ["\ud574\uc11d", "\uc694\uc57d", "insight", "\ud575\uc2ec"]):
        add("insight_bullets")
    if _contains(text, ["\ucd94\ucc9c", "\uc870\uce58", "\uac1c\uc120", "\ub2e4\uc74c \ud655\uc778", "recommend"]):
        add("recommendation_list")

    complexity = "auto"
    if _contains(text, ["\uac04\ub2e8", "\uc9e7\uac8c", "\uc694\uc57d\ub9cc", "simple", "brief"]):
        complexity = "simple"
    elif _contains(text, ["\uc0c1\uc138", "\ud48d\ubd80", "\ub9ce\uc774", "\uc804\uccb4", "detailed", "full"]):
        complexity = "detailed"
    elif _contains(text, ["\ucd18\ucd18", "\uc791\uac8c", "compact"]):
        complexity = "compact"

    target_block_count = _target_block_count(text, requested_blocks, complexity)
    return {
        "source": "rule_based_keyword_hint",
        "confidence": "low",
        "usage_note": "Raw question and view_request must win over this hint; use it only for deterministic fallback drafts.",
        "raw_text": raw_view_request,
        "complexity": complexity,
        "requested_blocks": requested_blocks,
        "target_block_count": target_block_count,
        "style_keywords": _style_keywords(text),
    }


def _target_block_count(text: str, requested_blocks: list[str], complexity: str) -> int:
    """요청 문장과 선택된 요소를 보고 목표 블록 수를 정합니다."""

    explicit = _explicit_count(text)
    if explicit:
        # 사용자가 KPI/차트/표 같은 콘텐츠 요소를 함께 적은 경우에는
        # 보고서 헤더와 데이터 범위 요약이 앞에서 잘라먹지 않도록 여유를 둡니다.
        content_floor = len(requested_blocks) + 2 if requested_blocks else explicit
        return max(3, min(max(explicit, content_floor), 10))
    if complexity == "simple":
        return 5
    if complexity == "detailed":
        return 10
    base_count = 2 + len(requested_blocks)
    if "insight_bullets" not in requested_blocks and _contains(text, ["\ud574\uc11d", "\uc694\uc57d", "\ub9ac\ud3ec\ud2b8", "report"]):
        base_count += 1
    return max(5, min(base_count, 10))


def _explicit_count(text: str) -> int:
    """'5개', '5 blocks'처럼 직접 적은 개수를 읽습니다."""

    import re

    match = re.search(r"(\d{1,2})\s*(?:\uac1c|blocks?|components?|\ube14\ub85d|\uc694\uc18c)", text)
    return int(match.group(1)) if match else 0


def _style_keywords(text: str) -> list[str]:
    """색상/분위기 관련 표현을 모읍니다."""

    result: list[str] = []
    for keyword in ["\ud30c\ub780\uc0c9", "\ucd08\ub85d", "\ud68c\uc0c9", "\ube68\uac04\uc0c9", "\uacbd\uace0", "\uac15\uc870", "\ucc28\ubd84\ud55c", "\uae54\ub054\ud55c", "\uc784\uc6d0\uc6a9", "compact", "comfortable"]:
        if keyword.lower() in text and keyword not in result:
            result.append(keyword)
    return result


def _contains(text: str, needles: list[str]) -> bool:
    """문장 안에 지정한 키워드 중 하나라도 포함됐는지 확인합니다."""

    haystack = str(text or "").lower()
    return any(needle.lower() in haystack for needle in needles)


def _select_input_text(data_text: str, file_data: Any) -> str:
    """직접 입력 텍스트와 File Read 결과 중 실제로 사용할 텍스트를 고릅니다."""

    direct = str(data_text or "").strip()
    file_text = _extract_text(file_data).strip()
    return direct or file_text


def _extract_text(value: Any) -> str:
    """Langflow의 다양한 데이터 객체에서 가능한 텍스트 내용을 꺼냅니다.

    File Read 컴포넌트는 Langflow 버전/파일 유형에 따라 Data, Message, DataFrame 등
    서로 다른 모양으로 값을 넘길 수 있습니다. 그래서 흔히 쓰이는 속성과 key를
    차례로 확인하면서 CSV/JSON으로 변환 가능한 값을 찾습니다.
    """

    if value is None:
        return ""
    if isinstance(value, str):
        return value
    if hasattr(value, "to_csv"):
        try:
            # pandas DataFrame처럼 `to_csv`가 있으면 CSV 문자열로 바꿉니다.
            return value.to_csv(index=False)
        except Exception:
            pass
    if hasattr(value, "to_dict"):
        try:
            # pandas DataFrame처럼 `to_dict`가 있으면 row dict 목록으로 바꿉니다.
            rows = value.to_dict(orient="records")
            if isinstance(rows, list):
                return json.dumps(rows, ensure_ascii=False, default=str)
        except Exception:
            pass
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        for key in ("text", "content", "data", "raw", "file_content", "file_contents"):
            if isinstance(data.get(key), str):
                return data[key]
        for key in ("dataframe", "structured_content", "structuredContent"):
            if data.get(key) is not None:
                extracted = _extract_text(data.get(key))
                if extracted:
                    return extracted
        if isinstance(data.get("rows"), list):
            return json.dumps(data, ensure_ascii=False, default=str)
        if isinstance(data.get("records"), list):
            return json.dumps(data["records"], ensure_ascii=False, default=str)
        if isinstance(data.get("columns"), list) and isinstance(data.get("data"), list):
            return json.dumps(data, ensure_ascii=False, default=str)
    if isinstance(data, list):
        return json.dumps(data, ensure_ascii=False, default=str)
    for attr in ("text", "content"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text
    for attr in ("dataframe", "structured_content", "structuredContent", "value"):
        nested = getattr(value, attr, None)
        if nested is not None and nested is not value:
            extracted = _extract_text(nested)
            if extracted:
                return extracted
    if isinstance(value, dict):
        return json.dumps(value, ensure_ascii=False, default=str)
    if isinstance(value, list):
        return json.dumps(value, ensure_ascii=False, default=str)
    return str(value)


def _parse_datasets(text: str) -> list[dict[str, Any]]:
    """입력 문자열을 데이터셋 목록으로 파싱합니다.

    우선 JSON을 시도하고, 실패하면 JSONL, 마지막으로 CSV로 해석합니다.
    아무 입력도 없으면 빈 demo 데이터셋을 만들어 flow가 끊기지 않게 합니다.
    """

    raw = str(text or "").strip()
    if not raw:
        return [_dataset("demo_dataset", "입력 데이터", [], [])]
    parsed = _try_json(raw)
    if parsed is not None:
        return _datasets_from_json(parsed)
    parsed_rows = _try_jsonl(raw)
    if parsed_rows is not None:
        return [_dataset("demo_dataset", "입력 데이터", _columns_from_rows(parsed_rows), parsed_rows)]
    rows = _parse_csv(raw)
    return [_dataset("demo_dataset", "입력 데이터", _columns_from_rows(rows), rows)]


def _datasets_from_json(value: Any) -> list[dict[str, Any]]:
    """JSON 값에서 rows/columns/data_ref 구조를 찾아 데이터셋 목록으로 바꿉니다."""

    if isinstance(value, list):
        if all(isinstance(item, dict) for item in value):
            return [_dataset("demo_dataset", "입력 데이터", _columns_from_rows(value), value)]
        return [_dataset("demo_dataset", "입력 데이터", ["value"], [{"value": item} for item in value])]
    if not isinstance(value, dict):
        return [_dataset("demo_dataset", "입력 데이터", ["value"], [{"value": value}])]

    if isinstance(value.get("datasets"), list):
        datasets = []
        for index, item in enumerate(value["datasets"], start=1):
            if not isinstance(item, dict):
                continue
            rows = _rows(item.get("rows") or _dict(item.get("data")).get("rows"))
            columns = _strings(item.get("columns")) or _strings(_dict(item.get("data")).get("columns")) or _columns_from_rows(rows)
            datasets.append(
                _dataset(
                    str(item.get("dataset_id") or item.get("id") or f"dataset_{index}"),
                    str(item.get("label") or item.get("name") or item.get("dataset_id") or f"Dataset {index}"),
                    columns,
                    rows,
                    data_ref=_dict(item.get("data_ref")),
                    row_count=_positive_int(item.get("row_count"), len(rows)),
                )
            )
        return datasets or [_dataset("demo_dataset", "입력 데이터", [], [])]

    data = _dict(value.get("data"))
    rows = _rows(value.get("rows") or data.get("rows"))
    columns = _strings(value.get("columns")) or _strings(data.get("columns")) or _columns_from_rows(rows)
    return [
        _dataset(
            str(value.get("dataset_id") or value.get("id") or "demo_dataset"),
            str(value.get("label") or value.get("name") or "입력 데이터"),
            columns,
            rows,
            data_ref=_dict(value.get("data_ref") or data.get("data_ref")),
            row_count=_positive_int(value.get("row_count") or data.get("row_count"), len(rows)),
        )
    ]


def _try_json(text: str) -> Any | None:
    """문자열 전체를 JSON으로 읽어 봅니다. 실패하면 None을 반환합니다."""

    try:
        return json.loads(text)
    except Exception:
        return None


def _try_jsonl(text: str) -> list[dict[str, Any]] | None:
    """한 줄에 JSON 객체 하나씩 있는 JSONL 형식을 읽어 봅니다."""

    rows = []
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            parsed = json.loads(line)
        except Exception:
            return None
        if not isinstance(parsed, dict):
            return None
        rows.append(parsed)
    return rows if rows else None


def _parse_csv(text: str) -> list[dict[str, Any]]:
    """CSV 문자열을 dict row 목록으로 변환합니다."""

    sample = text[:2048]
    try:
        # 구분자가 쉼표인지 탭인지 등을 csv.Sniffer가 샘플을 보고 추정합니다.
        dialect = csv.Sniffer().sniff(sample)
    except Exception:
        dialect = csv.excel
    reader = csv.DictReader(io.StringIO(text), dialect=dialect)
    return [_clean_row(row) for row in reader if isinstance(row, dict)]


def _clean_row(row: dict[str, Any]) -> dict[str, Any]:
    """CSV row에서 빈 컬럼명은 제거하고 값은 숫자면 숫자로 변환합니다."""

    return {str(key or "").strip(): _coerce(value) for key, value in row.items() if str(key or "").strip()}


def _coerce(value: Any) -> Any:
    """문자열 값을 가능한 경우 int/float 숫자로 바꿉니다."""

    text = str(value or "").strip()
    if text == "":
        return ""
    normalized = text.replace(",", "")
    try:
        number = float(normalized)
    except Exception:
        return text
    return int(number) if number.is_integer() else number


def _dataset(
    dataset_id: str,
    label: str,
    columns: list[str],
    rows: list[dict[str, Any]],
    data_ref: dict[str, Any] | None = None,
    row_count: int | None = None,
) -> dict[str, Any]:
    """뒤 노드들이 기대하는 데이터셋 딕셔너리 형식을 만듭니다."""

    return {
        "dataset_id": str(dataset_id or "demo_dataset"),
        "label": str(label or dataset_id or "Demo Dataset"),
        "columns": columns,
        "rows": rows,
        "row_count": len(rows) if row_count is None else int(row_count),
        "data_ref": data_ref or {},
    }


def _build_data_views(
    datasets: list[dict[str, Any]],
    question: str = "",
    view_request: str = "",
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], dict[str, Any]]:
    """여러 dataset을 렌더러가 사용할 수 있는 data view 목록으로 변환합니다.

    - 단일 dataset이면 기존과 동일하게 해당 rows를 active view로 사용합니다.
    - 여러 dataset이면 개별 view를 유지하면서, 공통 key가 있으면 자동 join view를 추가합니다.
    - 같은 구조의 dataset 묶음이면 union view도 만들 수 있습니다.
    """

    normalized = [deepcopy(item) for item in datasets if isinstance(item, dict)]
    if not normalized:
        normalized = [_dataset("demo_dataset", "입력 데이터", [], [])]

    views = [_view_from_dataset(item) for item in normalized]
    candidates = _relationship_candidates(normalized)
    intent_text = f"{question} {view_request}".lower()
    union_view = _union_view(normalized)
    join_view = _joined_view(normalized, candidates)

    if union_view:
        views.append(union_view)
    if join_view:
        views.append(join_view)

    active = views[0]
    if len(normalized) > 1:
        if _contains_text(intent_text, ["union", "append", "concat", "세로", "합쳐", "누적"]) and union_view:
            active = union_view
        elif join_view:
            active = join_view
        elif union_view:
            active = union_view
    return views, candidates, active


def _view_from_dataset(dataset: dict[str, Any]) -> dict[str, Any]:
    """하나의 원본 dataset을 select 전략 data view로 감쌉니다."""

    rows = _rows(dataset.get("rows"))
    columns = _strings(dataset.get("columns")) or _columns_from_rows(rows)
    dataset_id = str(dataset.get("dataset_id") or "demo_dataset")
    return {
        "data_view_id": dataset_id,
        "label": str(dataset.get("label") or dataset_id),
        "strategy": "select",
        "source_dataset_ids": [dataset_id],
        "join_keys": [],
        "columns": columns,
        "rows": rows,
        "row_count": _positive_int(dataset.get("row_count"), len(rows)),
        "data_ref": _dict(dataset.get("data_ref")),
    }


def _relationship_candidates(datasets: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """dataset 쌍 사이의 공통 key 후보를 찾습니다."""

    candidates = []
    for left_index, left in enumerate(datasets):
        for right in datasets[left_index + 1 :]:
            keys = _common_join_keys(left, right)
            candidates.append(
                {
                    "left_dataset": str(left.get("dataset_id") or ""),
                    "right_dataset": str(right.get("dataset_id") or ""),
                    "join_keys": keys,
                    "confidence": "high" if keys else "none",
                    "reason": "공통 key 후보가 있어 자동 결합할 수 있습니다." if keys else "공통 key 후보가 부족해 자동 결합하지 않습니다.",
                }
            )
    return candidates


def _common_join_keys(left: dict[str, Any], right: dict[str, Any]) -> list[str]:
    """두 dataset 사이에서 join key로 쓰기 좋은 공통 컬럼을 고릅니다."""

    left_rows = _rows(left.get("rows"))
    right_rows = _rows(right.get("rows"))
    common = [
        column
        for column in _strings(left.get("columns")) or _columns_from_rows(left_rows)
        if column in set(_strings(right.get("columns")) or _columns_from_rows(right_rows))
    ]
    preferred = []
    for column in common:
        if _looks_like_join_key(column, left_rows, right_rows):
            preferred.append(column)
    if preferred:
        return preferred[:4]
    # 컬럼명이 같고 값이 숫자 metric처럼 보이지 않는 경우를 마지막 후보로 사용합니다.
    fallback = [column for column in common if not _looks_numeric_metric(column, left_rows + right_rows)]
    return fallback[:3]


def _looks_like_join_key(column: str, left_rows: list[dict[str, Any]], right_rows: list[dict[str, Any]]) -> bool:
    """컬럼명과 값 분포를 보고 join key 가능성을 판단합니다."""

    text = str(column or "").lower()
    if any(token in text for token in ["date", "dt", "day", "month", "week", "year", "날짜", "일자", "기준일"]):
        return True
    if any(token in text for token in ["process", "oper", "line", "product", "item", "category", "shift", "region", "warehouse", "공정", "라인", "제품", "구분"]):
        return True
    if any(token in text for token in ["id", "code", "key", "no", "seq", "코드", "번호"]):
        return True
    return not _looks_numeric_metric(column, left_rows + right_rows)


def _looks_numeric_metric(column: str, rows: list[dict[str, Any]]) -> bool:
    """값 대부분이 숫자이고 key 이름이 아니면 metric 컬럼으로 봅니다."""

    values = [row.get(column) for row in rows if row.get(column) not in (None, "")]
    if not values:
        return False
    if any(token in str(column).lower() for token in ["id", "code", "no", "seq", "date", "dt"]):
        return False
    numeric_count = sum(1 for value in values if isinstance(value, (int, float)) and not isinstance(value, bool))
    return numeric_count / max(len(values), 1) >= 0.8


def _joined_view(datasets: list[dict[str, Any]], candidates: list[dict[str, Any]]) -> dict[str, Any] | None:
    """여러 dataset을 공통 key 기준으로 outer join한 view를 만듭니다."""

    if len(datasets) < 2:
        return None
    common_keys = set(_strings(candidates[0].get("join_keys")) if candidates else [])
    for candidate in candidates[1:]:
        common_keys &= set(_strings(candidate.get("join_keys")))
    join_keys = [column for column in (_strings(datasets[0].get("columns")) or _columns_from_rows(_rows(datasets[0].get("rows")))) if column in common_keys]
    if not join_keys:
        return None

    joined_by_key: dict[tuple[str, ...], dict[str, Any]] = {}
    output_columns = list(join_keys)
    source_ids = [str(item.get("dataset_id") or f"dataset_{index}") for index, item in enumerate(datasets, start=1)]
    non_key_counts: dict[str, int] = {}
    for dataset in datasets:
        for column in _strings(dataset.get("columns")) or _columns_from_rows(_rows(dataset.get("rows"))):
            if column not in join_keys:
                non_key_counts[column] = non_key_counts.get(column, 0) + 1

    for dataset in datasets:
        dataset_id = str(dataset.get("dataset_id") or "")
        rows = _rows(dataset.get("rows"))
        for row in rows:
            key = tuple(str(row.get(column, "")) for column in join_keys)
            target = joined_by_key.setdefault(key, {column: row.get(column, "") for column in join_keys})
            for column, value in row.items():
                if column in join_keys:
                    continue
                output_name = _merged_column_name(column, dataset_id, non_key_counts.get(column, 0) > 1, output_columns)
                target[output_name] = value
                if output_name not in output_columns:
                    output_columns.append(output_name)

    rows = list(joined_by_key.values())
    label = " + ".join(str(item.get("label") or item.get("dataset_id") or "") for item in datasets[:3])
    return {
        "data_view_id": "joined_auto",
        "label": f"자동 결합 데이터 ({label})",
        "strategy": "join",
        "source_dataset_ids": source_ids,
        "join_keys": join_keys,
        "columns": output_columns,
        "rows": rows,
        "row_count": len(rows),
        "data_ref": {},
    }


def _merged_column_name(column: str, dataset_id: str, duplicated: bool, output_columns: list[str]) -> str:
    """join 시 같은 이름의 metric이 충돌하면 dataset_id suffix를 붙입니다."""

    if not duplicated:
        return column
    suffix = "".join(ch if ch.isalnum() else "_" for ch in str(dataset_id or "dataset")).strip("_") or "dataset"
    return f"{column}__{suffix}"


def _union_view(datasets: list[dict[str, Any]]) -> dict[str, Any] | None:
    """같은 구조의 여러 dataset을 세로로 붙인 union view를 만듭니다."""

    if len(datasets) < 2:
        return None
    column_sets = [set(_strings(item.get("columns")) or _columns_from_rows(_rows(item.get("rows")))) for item in datasets]
    if not column_sets or len({tuple(sorted(cols)) for cols in column_sets}) != 1:
        return None
    columns = list(_strings(datasets[0].get("columns")) or _columns_from_rows(_rows(datasets[0].get("rows"))))
    output_columns = ["__dataset_id", "__dataset_label", *columns]
    rows = []
    for dataset in datasets:
        dataset_id = str(dataset.get("dataset_id") or "")
        label = str(dataset.get("label") or dataset_id)
        for row in _rows(dataset.get("rows")):
            rows.append({"__dataset_id": dataset_id, "__dataset_label": label, **{column: row.get(column, "") for column in columns}})
    return {
        "data_view_id": "union_auto",
        "label": "자동 통합 데이터",
        "strategy": "union",
        "source_dataset_ids": [str(item.get("dataset_id") or "") for item in datasets],
        "join_keys": [],
        "columns": output_columns,
        "rows": rows,
        "row_count": len(rows),
        "data_ref": {},
    }


def _contains_text(text: str, needles: list[str]) -> bool:
    """문장에 특정 단어가 하나라도 포함되어 있는지 확인합니다."""

    haystack = str(text or "").lower()
    return any(needle.lower() in haystack for needle in needles)


def _select_dataset(datasets: list[dict[str, Any]]) -> dict[str, Any]:
    """현재 체험 flow에서는 첫 번째 데이터셋을 분석 대상으로 선택합니다."""

    return deepcopy(datasets[0]) if datasets else _dataset("demo_dataset", "Demo Dataset", [], [])


def _rows(value: Any) -> list[dict[str, Any]]:
    """값이 dict 목록이면 안전하게 복사해서 반환하고, 아니면 빈 목록을 반환합니다."""

    return [deepcopy(row) for row in value if isinstance(row, dict)] if isinstance(value, list) else []


def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    """rows에 실제로 등장한 컬럼명을 처음 나온 순서대로 모읍니다."""

    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


def _strings(value: Any) -> list[str]:
    """문자열 목록만 깨끗하게 정리하고 중복을 제거합니다."""

    if not isinstance(value, list):
        return []
    result = []
    for item in value:
        text = str(item or "").strip()
        if text and text not in result:
            result.append(text)
    return result


def _dict(value: Any) -> dict[str, Any]:
    """값이 dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _positive_int(value: Any, default: int) -> int:
    """정수로 변환하되 음수는 0으로 보정합니다."""

    try:
        parsed = int(value)
    except Exception:
        parsed = default
    return max(0, parsed)


class DemoReportRequestLoader(Component):
    """Langflow 화면에 표시되는 00번 커스텀 컴포넌트 클래스."""

    display_name = "00 리포트 요청/데이터 불러오기"
    description = "질문, 표시 요청, 직접 입력 데이터 또는 File Read 결과를 HTML 리포트용 요청으로 정리합니다."
    icon = "FileInput"
    inputs = [
        MessageTextInput(name="question", display_name="질문", required=True),
        MessageTextInput(name="view_request", display_name="보고 싶은 방식", required=False),
        MessageTextInput(name="data_text", display_name="데이터 직접 입력", required=False),
        DataInput(
            name="file_data",
            display_name="파일 데이터",
            input_types=[
                "Data",
                "DataFrame",
                "Message",
                "Text",
                "File",
                "JSON",
                "StructuredContent",
                "Structured Content",
            ],
            required=False,
        ),
    ]
    outputs = [Output(name="payload", display_name="요청 데이터", method="build_payload")]

    def build_payload(self) -> Data:
        """Langflow가 이 노드를 실행할 때 호출하는 출력 생성 함수입니다."""

        result = build_demo_report_request(
            getattr(self, "question", ""),
            getattr(self, "view_request", ""),
            getattr(self, "data_text", ""),
            getattr(self, "file_data", None),
        )
        self.status = {
            "datasets": len(result.get("available_datasets", [])),
            "selected": (result.get("request") or {}).get("selected_dataset_id"),
            "rows": ((result.get("api_response") or {}).get("data") or {}).get("row_count", 0),
        }
        return Data(data=result)

from __future__ import annotations

"""01 데이터 구조 분석 노드.

이 파일은 00번 노드가 만든 rows/columns 데이터를 훑어서
어떤 컬럼이 숫자 metric인지, 어떤 컬럼이 날짜 축인지, 어떤 컬럼이 범주/상태인지
추정합니다. 이 분석 결과는 02번 요소 추천과 03번 리포트 계획 생성의 근거가 됩니다.
"""

import json
import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data


# 컬럼명에 자주 등장하는 단어를 보고 의미를 추정하기 위한 정규식입니다.
# 예: `DATE`, `기준일`은 시간축 후보, `STATUS`, `오류`는 상태/예외 후보가 됩니다.
DATE_RE = re.compile(r"date|dt|time|day|week|month|year|날짜|일자|기준일|월|주차|시간", re.I)
ID_RE = re.compile(r"(^|_)(id|key|code|no|seq)($|_)|코드|번호|식별", re.I)
DELTA_RE = re.compile(r"delta|diff|change|증감|변화|차이|gap|rate|ratio|percent|%|율", re.I)
STATUS_RE = re.compile(r"status|state|flag|error|warning|issue|risk|상태|오류|경고|이상|위험", re.I)


def build_data_profile(analysis_payload: Any, question: str = "") -> dict[str, Any]:
    """입력 payload를 분석해서 리포트 계획에 필요한 데이터 프로파일을 만듭니다.

    주요 결과:
    - `columns`: 각 컬럼의 타입 추정 결과와 샘플 값
    - `column_groups`: 숫자/범주/날짜/상태 컬럼 묶음
    - `question_hints`: 질문 문구에서 요약/비교/추이 등의 의도 힌트
    - `report_signals`: 어떤 리포트 요소가 필요할지 판단하는 신호
    """

    payload = _payload(analysis_payload)
    request = _dict(payload.get("request"))
    resolved_question = str(question or "").strip() or str(request.get("question") or payload.get("question") or "").strip()
    view_request = str(request.get("view_request") or payload.get("view_request") or "").strip()
    intent_text = " ".join(text for text in (resolved_question, view_request) if text)
    api = _dict(payload.get("api_response")) or payload
    data = _dict(api.get("data")) or _dict(payload.get("data"))
    rows = _rows(data.get("rows")) or _rows(api.get("rows")) or _rows(payload.get("rows"))
    columns = _strings(data.get("columns")) or _strings(api.get("columns")) or _columns_from_rows(rows)
    row_count = _int(data.get("row_count"), _int(api.get("row_count"), len(rows)))
    data_ref = _dict(data.get("data_ref")) or _dict(api.get("data_ref"))
    warnings = _unique([*_list(payload.get("warnings")), *_list(api.get("warnings"))])
    errors = _unique([*_list(payload.get("errors")), *_list(api.get("errors"))])
    data_views = _list(payload.get("data_views"))
    available_data_views = _list(payload.get("available_data_views"))
    relationship_candidates = _list(payload.get("relationship_candidates"))
    # 너무 많은 row를 모두 훑으면 Langflow 실행이 무거워질 수 있어 앞 200개만 샘플로 분석합니다.
    column_profiles = [_profile_column(column, rows[:200]) for column in columns]
    groups = _groups(column_profiles)
    hints = _hints(intent_text)
    shape = {
        "row_count": row_count,
        "preview_row_count": len(rows),
        "column_count": len(columns),
        "data_is_preview": bool(data.get("data_is_preview") or api.get("data_is_preview") or row_count > len(rows)),
        "data_ref_present": bool(data_ref),
        "data_ref_loaded": bool(data.get("data_ref_loaded") or api.get("data_ref_loaded")),
        "data_ref_load_mode": data.get("data_ref_load_mode") or api.get("data_ref_load_mode") or "",
        "active_data_view_id": data.get("data_view_id") or request.get("active_data_view_id") or "",
        "active_data_view_strategy": data.get("strategy") or "",
    }
    signals = {
        "has_numeric_metrics": bool(groups["numeric_columns"]),
        "has_dimensions": bool(groups["dimension_columns"]),
        "has_time_axis": bool(groups["time_columns"]),
        "has_delta_or_rate": bool(groups["delta_columns"]),
        "has_status_or_exception": bool(groups["status_columns"] or warnings or errors),
        "looks_like_query_result": hints["detail"] or (row_count > 0 and not hints["summary"]),
        "looks_like_aggregate_result": row_count <= 50 and bool(groups["numeric_columns"]),
        "needs_preview_warning": bool(shape["data_is_preview"] or warnings or errors),
    }
    return {
        "profile_version": "html-report-data-profile-v1",
        "question": resolved_question,
        "view_request": view_request,
        "intent_text": intent_text,
        "shape": shape,
        "columns": column_profiles,
        "column_groups": groups,
        "question_hints": hints,
        "report_signals": signals,
        "available_datasets": _list(payload.get("available_datasets")),
        "available_data_views": available_data_views,
        "relationship_candidates": relationship_candidates,
        "data_view_profiles": [_profile_data_view(view) for view in data_views[:8] if isinstance(view, dict)],
        "data_ref": data_ref,
        "warnings": warnings,
        "errors": errors,
        "preview_rows": deepcopy(rows[:10]),
    }


def _profile_data_view(view: dict[str, Any]) -> dict[str, Any]:
    """여러 데이터셋/결합 view를 LLM이 이해할 수 있도록 작게 요약합니다."""

    rows = _rows(view.get("rows"))
    columns = _strings(view.get("columns")) or _columns_from_rows(rows)
    profiles = [_profile_column(column, rows[:120]) for column in columns]
    return {
        "data_view_id": str(view.get("data_view_id") or ""),
        "label": str(view.get("label") or view.get("data_view_id") or ""),
        "strategy": str(view.get("strategy") or "select"),
        "source_dataset_ids": _strings(view.get("source_dataset_ids")),
        "join_keys": _strings(view.get("join_keys")),
        "shape": {
            "row_count": _int(view.get("row_count"), len(rows)),
            "preview_row_count": len(rows),
            "column_count": len(columns),
        },
        "columns": [
            {
                "name": item.get("name"),
                "inferred_type": item.get("inferred_type"),
                "semantic_hint": item.get("semantic_hint", ""),
                "sample_values": _list(item.get("sample_values"))[:3],
                "top_values": _list(item.get("top_values"))[:8],
                "numeric_stats": _dict(item.get("numeric_stats")),
            }
            for item in profiles
        ],
        "column_groups": _groups(profiles),
        "preview_rows": deepcopy(rows[:3]),
    }


def _profile_column(column: str, rows: list[dict[str, Any]]) -> dict[str, Any]:
    """한 컬럼의 값 분포를 보고 타입, 결측 수, 샘플 값, 숫자 통계를 계산합니다."""

    values = [row.get(column) for row in rows]
    non_empty = [value for value in values if value not in (None, "", [], {})]
    unique_values = _unique(non_empty)
    inferred = _infer_type(column, non_empty, unique_values)
    numeric_values = [number for number in (_number(value) for value in non_empty) if number is not None]
    result: dict[str, Any] = {
        "name": column,
        "inferred_type": inferred,
        "non_empty_count": len(non_empty),
        "null_count": len(values) - len(non_empty),
        "unique_count": len(unique_values),
        "sample_values": _sample(non_empty),
        "top_values": _top_values(non_empty),
        "is_metric_candidate": inferred == "numeric",
        "is_dimension_candidate": inferred in {"dimension", "id", "status"},
        "is_time_candidate": inferred == "time",
        "is_text_candidate": inferred == "text",
    }
    if DELTA_RE.search(column):
        # 증감률/변화량처럼 보이는 컬럼은 카드나 해석에서 별도로 활용할 수 있게 표시합니다.
        result["semantic_hint"] = "delta_or_rate"
    if STATUS_RE.search(column):
        # 오류/경고/상태 컬럼은 예외 테이블 후보가 됩니다.
        result["semantic_hint"] = "status_or_exception"
    if numeric_values:
        result["numeric_stats"] = {
            "min": min(numeric_values),
            "max": max(numeric_values),
            "sum": sum(numeric_values),
            "avg": sum(numeric_values) / len(numeric_values),
        }
    return result


def _infer_type(column: str, values: list[Any], unique_values: list[Any]) -> str:
    """컬럼명과 실제 값 샘플을 함께 보고 간단한 타입을 추정합니다."""

    if not values:
        return "empty"
    if DATE_RE.search(column) or _date_ratio(values) >= 0.6:
        return "time"
    if _numeric_ratio(values) >= 0.8:
        return "numeric"
    if STATUS_RE.search(column):
        return "status"
    if ID_RE.search(column) and len(unique_values) >= min(len(values), 20):
        return "id"
    if sum(len(str(value)) for value in values) / max(len(values), 1) >= 50:
        return "text"
    return "dimension"


def _groups(column_profiles: list[dict[str, Any]]) -> dict[str, list[str]]:
    """컬럼별 프로파일을 숫자/범주/날짜/상태 같은 그룹으로 다시 묶습니다."""

    groups = {
        "numeric_columns": [],
        "dimension_columns": [],
        "time_columns": [],
        "text_columns": [],
        "id_columns": [],
        "status_columns": [],
        "delta_columns": [],
    }
    for profile in column_profiles:
        name = str(profile.get("name") or "")
        inferred = profile.get("inferred_type")
        if inferred == "numeric":
            groups["numeric_columns"].append(name)
        if inferred in {"dimension", "status"}:
            groups["dimension_columns"].append(name)
        if inferred == "time":
            groups["time_columns"].append(name)
        if inferred == "text":
            groups["text_columns"].append(name)
        if inferred == "id":
            groups["id_columns"].append(name)
        if inferred == "status" or profile.get("semantic_hint") == "status_or_exception":
            groups["status_columns"].append(name)
        if profile.get("semantic_hint") == "delta_or_rate":
            groups["delta_columns"].append(name)
    return groups


def _hints(question: str) -> dict[str, bool]:
    """사용자 질문 문장에 포함된 단어로 리포트 의도를 추정합니다."""

    text = str(question or "").lower()
    return {
        "summary": _has(text, ["요약", "현황", "핵심", "주요", "지표", "카드", "summary", "overview", "kpi", "card"]),
        "comparison": _has(text, ["비교", "차이", "별", "막대", "그래프", "차트", "compare", "comparison", "versus", "vs", "bar", "chart"]),
        "trend": _has(text, ["추이", "변화", "기간", "날짜", "일별", "주별", "월별", "시계열", "선그래프", "선 그래프", "라인", "trend", "daily", "weekly", "monthly", "line", "timeline"]),
        "ranking": _has(text, ["상위", "하위", "top", "bottom", "순위", "랭킹", "가장 많은", "가장 적은"]),
        "detail": _has(text, ["상세", "목록", "리스트", "표", "테이블", "상세표", "row", "raw", "table", "원본", "그대로", "보여줘", "조회"]),
        "exception": _has(text, ["이상", "문제", "경고", "오류", "리스크", "초과", "미달", "exception", "error", "warning", "risk"]),
        "report": _has(text, ["리포트", "보고서", "html", "dashboard", "대시보드", "공유"]),
    }


def _has(text: str, needles: list[str]) -> bool:
    """문장 안에 후보 단어 중 하나라도 포함되어 있는지 확인합니다."""

    return any(needle.lower() in text for needle in needles)


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _rows(value: Any) -> list[dict[str, Any]]:
    """dict row 목록만 안전하게 복사해서 반환합니다."""

    return [deepcopy(row) for row in value if isinstance(row, dict)] if isinstance(value, list) else []


def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    """rows에 등장한 컬럼명을 중복 없이 수집합니다."""

    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


def _strings(value: Any) -> list[str]:
    """문자열 목록을 정리하고 중복을 제거합니다."""

    if not isinstance(value, list):
        return []
    result = []
    for item in value:
        text = str(item or "").strip()
        if text and text not in result:
            result.append(text)
    return result


def _dict(value: Any) -> dict[str, Any]:
    """dict가 아닌 값은 빈 dict로 바꿔 뒤 로직을 단순하게 만듭니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list/tuple/set이면 list로 바꾸고, 아니면 빈 list를 반환합니다."""

    return list(value) if isinstance(value, (list, tuple, set)) else []


def _int(value: Any, fallback: int = 0) -> int:
    """문자열/실수를 정수로 바꾸되 실패하면 fallback을 반환합니다."""

    if isinstance(value, bool):
        return fallback
    if isinstance(value, int):
        return value
    if isinstance(value, float) and value == value:
        return int(value)
    try:
        return int(str(value).replace(",", ""))
    except Exception:
        return fallback


def _number(value: Any) -> float | None:
    """값이 숫자로 해석 가능하면 float로, 아니면 None으로 반환합니다."""

    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)) and value == value:
        return float(value)
    text = str(value or "").strip().replace(",", "").replace("%", "")
    try:
        return float(text) if text else None
    except Exception:
        return None


def _numeric_ratio(values: list[Any]) -> float:
    """값 목록 중 숫자로 해석 가능한 값의 비율을 계산합니다."""

    return sum(1 for value in values if _number(value) is not None) / len(values) if values else 0.0


def _date_ratio(values: list[Any]) -> float:
    """값 목록 중 날짜처럼 보이는 값의 비율을 계산합니다."""

    return sum(1 for value in values if _looks_like_date(value)) / len(values) if values else 0.0


def _looks_like_date(value: Any) -> bool:
    """간단한 날짜 형식인지 확인합니다. 예: 2026-06-20, 20260620."""

    text = str(value or "").strip()
    return bool(re.match(r"^\d{4}[-/]\d{1,2}([-/]\d{1,2})?", text) or re.match(r"^\d{6}(\d{2})?$", text))


def _sample(values: list[Any], limit: int = 5) -> list[Any]:
    """중복을 제거한 샘플 값을 최대 limit개 반환합니다."""

    return _unique(values)[:limit]


def _top_values(values: list[Any], limit: int = 12) -> list[dict[str, Any]]:
    """범주/상태/코드 값의 빈도를 LLM이 이해하기 쉬운 형태로 요약합니다.

    예를 들어 `ALERT_LEVEL` 컬럼에 HIGH/WARN/NORMAL 값이 있으면
    LLM이 정확한 값 문자열을 사용해 filter_rules나 highlight_rules를 만들 수 있습니다.
    """

    counts: dict[str, dict[str, Any]] = {}
    for value in values:
        if value in (None, "", [], {}):
            continue
        signature = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        if signature not in counts:
            counts[signature] = {"value": deepcopy(value), "count": 0}
        counts[signature]["count"] += 1
    ranked = sorted(counts.values(), key=lambda item: (-int(item["count"]), str(item["value"])))
    return ranked[:limit]


def _unique(values: list[Any]) -> list[Any]:
    """값 목록에서 빈 값과 중복 값을 제거합니다."""

    result: list[Any] = []
    signatures: set[str] = set()
    for value in values:
        if value in (None, "", [], {}):
            continue
        signature = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        if signature not in signatures:
            signatures.add(signature)
            result.append(deepcopy(value))
    return result


class HtmlReportDataProfileBuilder(Component):
    """Langflow 화면에 표시되는 01번 커스텀 컴포넌트 클래스."""

    display_name = "01 데이터 구조 분석"
    description = "리포트에 쓸 컬럼 유형, 숫자/범주/날짜 후보, 데이터 품질 신호를 요약합니다."
    icon = "ScanSearch"
    inputs = [
        DataInput(name="analysis_payload", display_name="요청 데이터", required=True),
    ]
    outputs = [Output(name="data_profile", display_name="데이터 분석 결과", method="build_profile")]

    def build_profile(self) -> Data:
        """00번 요청 데이터를 받아 데이터 분석 결과를 출력합니다."""

        result = build_data_profile(getattr(self, "analysis_payload", None))
        groups = result.get("column_groups") or {}
        self.status = {
            "rows": (result.get("shape") or {}).get("row_count", 0),
            "columns": (result.get("shape") or {}).get("column_count", 0),
            "numeric": len(groups.get("numeric_columns", [])),
            "time": len(groups.get("time_columns", [])),
        }
        return Data(data=result)

from __future__ import annotations

"""03 기본 리포트 계획 노드.

이 파일은 02번에서 추천된 요소를 실제 렌더러가 이해할 수 있는 `report_plan`
형식으로 바꿉니다. 이 계획은 그대로 HTML 렌더링에 사용할 수도 있고,
03a/03b를 거쳐 LLM이 더 풍부하게 보완한 계획으로 바꿀 수도 있습니다.
"""

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


def build_auto_html_plan(payload_value: Any, data_profile_value: Any, component_catalog_value: Any, max_blocks: Any = "auto") -> dict[str, Any]:
    """요청 데이터, 데이터 프로파일, 요소 카탈로그를 합쳐 기본 report_plan을 만듭니다."""

    payload = _payload(payload_value)
    profile = _payload(data_profile_value)
    catalog = _payload(component_catalog_value)
    request = _dict(payload.get("request"))
    groups = _dict(profile.get("column_groups"))
    shape = _dict(profile.get("shape"))
    recommendations = _prioritize_recommendations(
        _list(catalog.get("recommended_components")),
        _strings(_dict(request.get("visual_request")).get("requested_blocks")),
    )
    max_count, max_count_source = _resolve_max_blocks(max_blocks, request, profile)

    title = _title(request, profile)
    blocks: list[dict[str, Any]] = []
    for recommendation in recommendations:
        # 추천된 component_id를 렌더러가 바로 사용할 block dict로 변환합니다.
        if not isinstance(recommendation, dict):
            continue
        block_id = str(recommendation.get("component_id") or "")
        block = _block_from_recommendation(block_id, recommendation, groups, shape)
        if block and not any(existing.get("block_id") == block_id for existing in blocks):
            blocks.append(block)
        if len(blocks) >= max_count:
            break

    if not blocks:
        # 추천 결과가 비어도 최소한 제목과 상세표는 나오도록 fallback 계획을 둡니다.
        blocks = [
            {"block_id": "report_header", "title": title},
            {"block_id": "detail_data_table", "title": "상세 데이터", "columns": _display_columns(groups, limit=12), "limit": 50},
        ]

    plan = {
        "plan_version": "html-report-plan-v1",
        "title": title,
        "subtitle": str(request.get("view_request") or request.get("question") or ""),
        "layout": _layout(request, profile),
        "composition": {
            "planning_role": "deterministic_fallback_draft",
            "target_block_count": max_count,
            "block_count_source": max_count_source,
            "visual_request": _dict(request.get("visual_request")),
            "llm_usage_note": "LLM should treat this as a safe draft only and prioritize raw question/view_request.",
        },
        "dataset_strategy": _dataset_strategy(payload, profile),
        "blocks": blocks,
        "warnings": _list(profile.get("warnings")),
    }
    plan = _apply_template_defaults(plan, catalog)
    result = _compact_report_payload(payload, profile)
    result["report_plan"] = plan
    # 03a 프롬프트 노드가 너무 큰 payload 전체를 보지 않아도 되도록 LLM용 요약을 따로 넣습니다.
    result["llm_context"] = _llm_context(profile, catalog)
    return result


def _apply_template_defaults(plan: dict[str, Any], catalog: dict[str, Any]) -> dict[str, Any]:
    """카탈로그 JSON에 들어온 기본 스타일/블록 기본값을 plan에 반영합니다."""

    defaults = _dict(catalog.get("template_defaults"))
    if not defaults:
        return plan
    result = deepcopy(plan)
    for key in ("audience", "report_goal", "layout"):
        value = defaults.get(key)
        if value and not result.get(key):
            result[key] = value
    for key in ("visual_style", "narrative"):
        value = _dict(defaults.get(key))
        if value:
            merged = _dict(result.get(key))
            merged.update(value)
            result[key] = merged
    block_defaults = _dict(defaults.get("block_defaults") or defaults.get("blocks"))
    if block_defaults:
        result["blocks"] = [_apply_block_default(block, block_defaults) for block in _list(result.get("blocks"))]
    return result


def _apply_block_default(block: Any, block_defaults: dict[str, Any]) -> Any:
    """특정 block_id에 대한 기본 설정을 하나의 block에 병합합니다."""

    if not isinstance(block, dict):
        return block
    block_id = str(block.get("block_id") or "")
    defaults = _dict(block_defaults.get(block_id))
    if not defaults:
        return block
    result = deepcopy(defaults)
    result.update(deepcopy(block))
    style = _dict(defaults.get("style"))
    style.update(_dict(block.get("style")))
    if style:
        result["style"] = style
    return result


def _prioritize_recommendations(recommendations: list[Any], preferred_ids: list[str]) -> list[dict[str, Any]]:
    """00번 표시 요구에서 직접 요청한 요소를 추천 목록 앞쪽으로 옮깁니다."""

    pinned_ids = {"report_header", "scope_summary"}
    by_id: dict[str, dict[str, Any]] = {}
    original_order: list[str] = []

    for item in recommendations:
        if not isinstance(item, dict):
            continue
        component_id = str(item.get("component_id") or "").strip()
        if not component_id:
            continue
        if component_id not in by_id:
            by_id[component_id] = item
            original_order.append(component_id)

    result: list[dict[str, Any]] = []

    def append_component(component_id: str) -> None:
        if not component_id or any(existing.get("component_id") == component_id for existing in result):
            return
        result.append(deepcopy(by_id.get(component_id) or {"component_id": component_id}))

    for component_id in original_order:
        if component_id in pinned_ids:
            append_component(component_id)
    for component_id in preferred_ids:
        if component_id not in pinned_ids:
            append_component(component_id)
    for component_id in original_order:
        append_component(component_id)
    return result


def _block_from_recommendation(block_id: str, recommendation: dict[str, Any], groups: dict[str, Any], shape: dict[str, Any]) -> dict[str, Any]:
    """추천 컴포넌트를 렌더러용 block 설정으로 변환합니다.

    예를 들어 `comparison_bar_chart` 추천은 x/y 컬럼, limit, chart_policy를 가진
    block dict로 바뀝니다. 필요한 컬럼이 부족하면 빈 dict를 반환해 건너뜁니다.
    """

    bindings = _dict(recommendation.get("suggested_bindings"))
    numeric = _strings(groups.get("numeric_columns"))
    dims = _strings(groups.get("dimension_columns"))
    times = _strings(groups.get("time_columns"))
    texts = _strings(groups.get("text_columns"))
    columns = _display_columns(groups, limit=12)

    if block_id == "report_header":
        return {"block_id": block_id, "title": "리포트 개요"}
    if block_id == "scope_summary":
        return {"block_id": block_id, "title": "데이터 범위"}
    if block_id == "warning_box":
        return {"block_id": block_id, "title": "확인 필요 사항"}
    if block_id == "empty_state":
        return {"block_id": block_id, "title": "조회 결과 없음"}
    if block_id == "kpi_card_grid":
        metrics = _list(bindings.get("metrics"))
        if not metrics:
            metrics = [{"label": column, "column": column, "aggregation": "sum"} for column in numeric[:4]]
        return {"block_id": block_id, "title": "주요 지표", "metrics": metrics[:4]}
    if block_id == "metric_delta_card_grid":
        metrics = _list(bindings.get("metrics")) or [{"label": column, "column": column, "aggregation": "avg"} for column in numeric[:4]]
        return {"block_id": block_id, "title": "증감 지표", "metrics": metrics[:4]}
    if block_id == "trend_line_chart" and times and numeric:
        return {"block_id": block_id, "title": "시간에 따른 변화", "x": str(bindings.get("x") or times[0]), "y": str(bindings.get("y") or numeric[0])}
    if block_id == "period_comparison_table":
        return {"block_id": block_id, "title": "기간별 상세 비교", "columns": _unique([*times[:1], *dims[:3], *numeric[:4], *texts[:2]])}
    if block_id == "comparison_bar_chart" and dims and numeric:
        return {
            "block_id": block_id,
            "title": "그룹별 비교",
            "x": str(bindings.get("x") or dims[0]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 10),
            "chart_policy": {"orientation": "horizontal", "show_values": True, "limit": _positive_int(bindings.get("limit"), 10)},
        }
    if block_id == "donut_chart" and dims and numeric:
        return {
            "block_id": block_id,
            "title": "구성비",
            "x": str(bindings.get("x") or dims[0]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "half",
            "chart_policy": {"show_percent": True, "show_legend": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "grouped_bar_chart" and dims and len(numeric) >= 2:
        metrics = _list(bindings.get("metrics")) or [{"label": column, "column": column, "aggregation": "sum"} for column in numeric[:3]]
        return {
            "block_id": block_id,
            "title": "복수 지표 비교",
            "x": str(bindings.get("x") or dims[0]),
            "metrics": metrics[:3],
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "full",
            "chart_policy": {"show_values": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "stacked_comparison_bar" and len(dims) >= 2 and numeric:
        return {
            "block_id": block_id,
            "title": "구성 비교",
            "x": str(bindings.get("x") or dims[0]),
            "series": str(bindings.get("series") or dims[1]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "chart_policy": {"show_legend": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "ranking_table" and numeric:
        sort = _dict(bindings.get("sort")) or {"by": numeric[0], "direction": "desc"}
        return {
            "block_id": block_id,
            "title": "상위 항목",
            "columns": _strings(bindings.get("columns")) or _unique([*dims[:4], *numeric[:4], *texts[:2]]),
            "sort": sort,
            "limit": _positive_int(bindings.get("limit"), 10),
        }
    if block_id == "detail_data_table":
        return {"block_id": block_id, "title": "상세 데이터", "columns": _strings(bindings.get("columns")) or columns, "limit": _positive_int(bindings.get("limit"), 50)}
    if block_id == "pivot_matrix_table" and len(dims) >= 2 and numeric:
        return {"block_id": block_id, "title": "교차표", "x": str(bindings.get("x") or dims[0]), "series": str(bindings.get("series") or dims[1]), "y": str(bindings.get("y") or numeric[0])}
    if block_id == "heatmap_matrix" and len(dims) >= 2 and numeric:
        return {
            "block_id": block_id,
            "title": "교차 히트맵",
            "x": str(bindings.get("x") or dims[0]),
            "series": str(bindings.get("series") or dims[1]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "full",
            "chart_policy": {"show_values": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "distribution_histogram" and numeric:
        return {
            "block_id": block_id,
            "title": "분포",
            "x": str(bindings.get("x") or bindings.get("column") or numeric[0]),
            "width": "half",
            "chart_policy": {"bin_count": _positive_int(bindings.get("bin_count"), 8), "show_values": True},
        }
    if block_id == "scatter_plot" and len(numeric) >= 2:
        return {
            "block_id": block_id,
            "title": "상관/산포",
            "x": str(bindings.get("x") or numeric[0]),
            "y": str(bindings.get("y") or numeric[1]),
            "limit": _positive_int(bindings.get("limit"), 120),
            "width": "half",
        }
    if block_id == "outlier_exception_table":
        status_columns = _strings(groups.get("status_columns"))
        return {"block_id": block_id, "title": "이상/예외 항목", "columns": _unique([*status_columns, *dims[:4], *numeric[:4], *texts[:2]]) or columns, "limit": 50}
    if block_id == "insight_bullets":
        return {"block_id": block_id, "title": "핵심 해석"}
    if block_id == "recommendation_list":
        return {"block_id": block_id, "title": "다음 확인 사항"}
    if block_id == "method_note":
        return {"block_id": block_id, "title": "생성 기준"}
    return {}


def _resolve_max_blocks(max_blocks: Any, request: dict[str, Any], profile: dict[str, Any]) -> tuple[int, str]:
    """수동 블록 수 대신 00번의 표시 요구를 우선 사용해 블록 수 제한을 정합니다."""

    raw = str(max_blocks or "auto").strip().lower()
    if raw not in {"", "auto", "\uc790\ub3d9"}:
        return max(3, min(_positive_int(max_blocks, 8), 10)), "manual"

    visual_request = _dict(request.get("visual_request"))
    try:
        target = int(visual_request.get("target_block_count") or 0)
    except Exception:
        target = 0
    if target:
        return max(3, min(target, 10)), "visual_request"

    text = " ".join(
        str(item or "")
        for item in (
            request.get("question"),
            request.get("view_request"),
            profile.get("intent_text"),
        )
    ).lower()
    if _contains(text, ["\uac04\ub2e8", "\uc9e7\uac8c", "simple", "brief"]):
        return 5, "auto_simple"
    if _contains(text, ["\uc0c1\uc138", "\ud48d\ubd80", "detailed", "full"]):
        return 10, "auto_detailed"
    return 8, "auto_default"


def _title(request: dict[str, Any], profile: dict[str, Any]) -> str:
    """질문 문장을 바탕으로 기본 리포트 제목을 만듭니다."""

    question = str(request.get("question") or profile.get("question") or "").strip()
    if "리포트" in question or "보고서" in question:
        return question[:80]
    if question:
        return f"{question[:60]} 리포트"
    return "HTML 데이터 리포트"


def _layout(request: dict[str, Any], profile: dict[str, Any]) -> str:
    """질문 힌트를 바탕으로 기본 레이아웃 유형을 고릅니다."""

    hints = _dict(profile.get("question_hints"))
    if hints.get("detail"):
        return "query_review"
    if hints.get("exception"):
        return "diagnosis"
    if hints.get("summary") or hints.get("comparison") or hints.get("trend"):
        return "dashboard"
    return "report"


def _display_columns(groups: dict[str, Any], limit: int) -> list[str]:
    """표나 LLM 컨텍스트에 보여줄 대표 컬럼을 고릅니다."""

    return _unique(
        [
            *_strings(groups.get("time_columns")),
            *_strings(groups.get("dimension_columns")),
            *_strings(groups.get("numeric_columns")),
            *_strings(groups.get("status_columns")),
            *_strings(groups.get("text_columns")),
        ]
    )[:limit]


def _compact_report_payload(payload: dict[str, Any], profile: dict[str, Any]) -> dict[str, Any]:
    """뒤 노드에 필요한 최소 payload만 남깁니다.

    앞 노드의 중복 정보를 모두 넘기면 Langflow 연결도 복잡하고 LLM 입력도 커지므로,
    요청/데이터/API 응답/요약 정도만 정리해 전달합니다.
    """

    shape = _dict(profile.get("shape"))
    groups = _dict(profile.get("column_groups"))
    api = _dict(payload.get("api_response"))
    data = _dict(api.get("data")) or _dict(payload.get("data"))
    result: dict[str, Any] = {
        "payload_version": payload.get("payload_version", "html-report-demo-v1"),
        "flow_type": payload.get("flow_type", "html_report_demo"),
        "status": payload.get("status", "ok"),
        "request": _dict(payload.get("request")),
        "available_datasets": _list(payload.get("available_datasets")),
        "available_data_views": _list(payload.get("available_data_views")),
        "data_views": _list(payload.get("data_views")),
        "relationship_candidates": _list(payload.get("relationship_candidates")),
        "api_response": {
            "status": api.get("status", payload.get("status", "ok")),
            "response_type": api.get("response_type", "demo_data"),
            "message": api.get("message", ""),
            "data": data,
        },
        "data_summary": {
            "row_count": shape.get("row_count", data.get("row_count", 0)),
            "preview_row_count": shape.get("preview_row_count", len(_list(data.get("rows")))),
            "column_count": shape.get("column_count", len(_list(data.get("columns")))),
            "data_is_preview": bool(shape.get("data_is_preview") or data.get("data_is_preview")),
            "numeric_columns": _strings(groups.get("numeric_columns")),
            "dimension_columns": _strings(groups.get("dimension_columns")),
            "time_columns": _strings(groups.get("time_columns")),
            "status_columns": _strings(groups.get("status_columns")),
            "active_data_view_id": shape.get("active_data_view_id") or data.get("data_view_id") or "",
            "active_data_view_strategy": shape.get("active_data_view_strategy") or data.get("strategy") or "",
        },
        "warnings": _list(payload.get("warnings")) or _list(profile.get("warnings")),
        "errors": _list(payload.get("errors")) or _list(profile.get("errors")),
    }
    return result


def _llm_context(profile: dict[str, Any], catalog: dict[str, Any]) -> dict[str, Any]:
