from __future__ import annotations

"""05-2 공유 링크 출력 노드.

이 파일은 04번 렌더러가 만든 HTML을 로컬 Report API 서버에 POST하고,
사용자에게 다운로드 링크와 만료 시간을 간단한 메시지로 보여줍니다.
"""

import json
import urllib.error
import urllib.request
from copy import deepcopy
from datetime import datetime, timedelta, timezone
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.message import Message


DEFAULT_TIMEOUT_SECONDS = 30


def publish_html_report(
    payload_value: Any,
    report_api_url: Any = "",
    ttl_hours: Any = "24",
) -> dict[str, Any]:
    """HTML 생성 결과를 Report API에 저장하고 링크 정보를 payload에 추가합니다."""

    payload = _payload(payload_value)
    if not payload:
        return {"report_publish": {"status": "error", "errors": ["empty payload"]}}

    html_report = _dict(payload.get("html_report"))
    report_plan = _dict(payload.get("report_plan"))
    request = _dict(payload.get("request"))
    html = _first_text(payload, html_report, ["html", "rendered_html", "html_string", "document_html"])
    if not html.strip():
        return {**payload, "report_publish": {"status": "error", "errors": ["html is empty"]}}

    base_url = _clean(report_api_url)
    if not base_url:
        return {**payload, "report_publish": {"status": "error", "errors": ["report_api_url is empty"]}}

    post_url = base_url.rstrip("/")
    if not post_url.endswith("/reports"):
        # 사용자가 `http://127.0.0.1:8010`만 넣어도 자동으로 `/reports`를 붙입니다.
        post_url = post_url + "/reports"

    create_request = {
        # server.py의 CreateReportRequest 모델과 같은 형식으로 맞춥니다.
        "html": html,
        "title": _clean(html_report.get("title") or report_plan.get("title") or payload.get("title") or "HTML Report"),
        "question": _clean(request.get("question") or payload.get("question")),
        "view_request": _clean(request.get("view_request") or payload.get("view_request") or html_report.get("view_request")),
        "available_datasets": _list(payload.get("available_datasets") or request.get("available_datasets")),
        "report_plan": report_plan,
        "ttl_hours": _positive_int(ttl_hours, 24),
        "filename_hint": _clean(
            html_report.get("filename_hint")
            or report_plan.get("filename_hint")
            or report_plan.get("title")
            or html_report.get("title")
            or "report"
        ),
    }

    try:
        response = _post_json(post_url, create_request, timeout=DEFAULT_TIMEOUT_SECONDS)
    except Exception as exc:
        # API 서버가 꺼져 있거나 URL이 틀려도 flow 전체가 죽지 않게 오류 payload를 반환합니다.
        return {**payload, "report_publish": {"status": "error", "errors": [str(exc)], "post_url": post_url}}

    next_html_report = _public_html_report(html_report, response)
    next_payload = _compact_publish_payload(payload, next_html_report)
    next_payload["report_publish"] = {
        "status": "published",
        "errors": [],
        "download_url": response.get("download_url", ""),
        "expires_at": response.get("expires_at", ""),
    }
    return next_payload


def build_report_link_message(payload_value: Any) -> str:
    """Report API 응답 payload를 사용자가 읽을 수 있는 짧은 링크 메시지로 바꿉니다."""

    payload = _payload(payload_value)
    html_report = _dict(payload.get("html_report"))
    publish = _dict(payload.get("report_publish"))
    title = _clean(html_report.get("title") or "HTML Report")
    download_url = _clean(html_report.get("download_url") or publish.get("download_url"))
    expires_at = _clean(html_report.get("expires_at") or publish.get("expires_at"))
    if download_url:
        lines = [f"HTML 리포트가 생성되었습니다: {title}", "", f"- 다운로드 링크: {download_url}"]
        if expires_at:
            lines.append(f"- 만료 시간: {_format_expires_at(expires_at)}")
        return "\n".join(lines)
    if publish.get("status") == "error":
        errors = "; ".join(str(item) for item in _list(publish.get("errors"))) or "알 수 없는 오류"
        return f"HTML은 생성했지만 Report API 링크 생성에 실패했습니다: {errors}"
    return "공유 링크가 아직 없습니다. 04 HTML 렌더링 결과와 Report API URL 연결을 확인하세요."


def _public_html_report(html_report: dict[str, Any], response: dict[str, Any]) -> dict[str, Any]:
    """뒤 노드/메시지에 필요한 공개 링크 정보만 남긴 html_report를 만듭니다."""

    return {
        "title": html_report.get("title", "HTML Report"),
        "download_url": response.get("download_url", ""),
        "expires_at": response.get("expires_at", ""),
    }


def _compact_publish_payload(payload: dict[str, Any], html_report: dict[str, Any]) -> dict[str, Any]:
    """링크 출력 이후 필요한 최소 정보만 담은 payload로 줄입니다."""

    return {
        "payload_version": payload.get("payload_version", "html-report-demo-v1"),
        "flow_type": payload.get("flow_type", "html_report_demo"),
        "status": payload.get("status", "ok"),
        "request": _dict(payload.get("request")),
        "html_report": html_report,
        "data_summary": _dict(payload.get("data_summary")),
        "warnings": _list(payload.get("warnings")),
        "errors": _list(payload.get("errors")),
    }


def _post_json(url: str, body: dict[str, Any], timeout: int) -> dict[str, Any]:
    """표준 라이브러리만 사용해 JSON POST 요청을 보냅니다.

    외부 패키지 `requests`가 없어도 동작하도록 `urllib.request`를 사용합니다.
    """

    data = json.dumps(body, ensure_ascii=False, default=str).encode("utf-8")
    request = urllib.request.Request(url, data=data, method="POST", headers={"Content-Type": "application/json"})
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            raw = response.read().decode("utf-8")
    except urllib.error.HTTPError as exc:
        detail = exc.read().decode("utf-8", errors="replace")
        raise RuntimeError(f"Report API HTTP {exc.code}: {detail}") from exc
    parsed = json.loads(raw or "{}")
    if not isinstance(parsed, dict):
        raise RuntimeError("Report API did not return a JSON object")
    return parsed


def _first_text(payload: dict[str, Any], html_report: dict[str, Any], keys: list[str]) -> str:
    """여러 후보 key 중 가장 먼저 발견되는 HTML 문자열을 찾습니다."""

    for source in (html_report, payload):
        for key in keys:
            value = source.get(key)
            if isinstance(value, str) and value.strip():
                return value
    return ""


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str):
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    """dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list면 복사본을, 아니면 빈 list를 반환합니다."""

    return deepcopy(value) if isinstance(value, list) else []


def _clean(value: Any) -> str:
    """값을 문자열로 바꾸고 앞뒤 공백을 제거합니다."""

    return str(value or "").strip()


def _format_expires_at(value: Any) -> str:
    """서버가 준 UTC 만료 시간을 한국 시간 문자열로 바꿉니다."""

    text = _clean(value)
    if not text:
        return ""
    try:
        parsed = datetime.fromisoformat(text.replace("Z", "+00:00"))
    except Exception:
        return text
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    kst = parsed.astimezone(timezone(timedelta(hours=9)))
    return kst.strftime("%Y-%m-%d %H:%M KST")


def _positive_int(value: Any, default: int) -> int:
    """값을 양의 정수로 바꾸고 실패하면 default를 사용합니다."""

    try:
        parsed = int(value)
    except Exception:
        parsed = default
    return max(1, parsed)


class ReportApiPublisher(Component):
    """Langflow 화면에 표시되는 05-2 커스텀 컴포넌트 클래스."""

    display_name = "05-2 공유 링크 출력"
    description = "생성된 HTML을 Report API에 저장하고 간단한 다운로드 링크 메시지를 출력합니다."
    icon = "ExternalLink"
    inputs = [
        DataInput(name="payload", display_name="HTML 생성 결과", required=True),
        MessageTextInput(name="report_api_url", display_name="Report API 주소", value="", advanced=False),
        MessageTextInput(name="ttl_hours", display_name="링크 유효시간", value="24", advanced=False),
    ]
    outputs = [Output(name="link_message", display_name="링크 메시지", method="build_message")]

    def _published_payload(self) -> dict[str, Any]:
        """같은 노드 실행 중 API POST가 중복 호출되지 않도록 결과를 캐시합니다."""

        cached = getattr(self, "_cached_publish_result", None)
        if isinstance(cached, dict):
            return cached
        result = publish_html_report(
            getattr(self, "payload", None),
            getattr(self, "report_api_url", ""),
            getattr(self, "ttl_hours", "24"),
        )
        self._cached_publish_result = result
        return result

    def build_message(self) -> Message:
        """공유 링크 메시지를 생성하고 Langflow status에 간단한 실행 상태를 표시합니다."""

        result = self._published_payload()
        publish = result.get("report_publish", {}) if isinstance(result, dict) else {}
        self.status = {
            "status": publish.get("status"),
            "download_url": publish.get("download_url", ""),
            "expires_at": publish.get("expires_at", ""),
            "errors": len(publish.get("errors", [])) if isinstance(publish.get("errors"), list) else 0,
        }
        return Message(text=build_report_link_message(result))

from __future__ import annotations

import hashlib
import json
import re
from typing import Any

from lfx.custom import Component
from lfx.io import BoolInput, DataInput, IntInput, Output
from lfx.schema import Data


def _as_bool(value: Any, default: bool = False) -> bool:
    if isinstance(value, bool):
        return value
    text = str(value or "").strip().lower()
    if text in {"1", "true", "yes", "y", "on"}:
        return True
    if text in {"0", "false", "no", "n", "off"}:
        return False
    return default


def _clamp_int(value: Any, default: int, minimum: int, maximum: int) -> int:
    try:
        number = int(value)
    except Exception:
        number = default
    return max(minimum, min(maximum, number))


def _payload_from_value(value: Any) -> dict[str, Any]:
    if value is None:
        return {}
    if isinstance(value, dict):
        return value
    if isinstance(value, list):
        return {"documents": value}

    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return data
    if isinstance(data, list):
        return {"documents": data}

    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(value, str):
        text = value
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {}
        if isinstance(parsed, dict):
            return parsed
        if isinstance(parsed, list):
            return {"documents": parsed}
    return {}


def _version_key(value: Any) -> tuple[tuple[int, Any], ...]:
    """Return a deterministic natural-sort key for common document versions."""
    text = str(value or "1").strip().lower()
    parts = re.findall(r"\d+|[^\d]+", text)
    key: list[tuple[int, Any]] = []
    for part in parts:
        cleaned = part.strip("._+- ")
        if not cleaned:
            continue
        if cleaned.isdigit():
            key.append((1, int(cleaned)))
        else:
            key.append((0, cleaned))
    return tuple(key) or ((1, 1),)


def _string_list(value: Any) -> list[str]:
    values = value if isinstance(value, list) else [value]
    result: list[str] = []
    for item in values:
        text = str(item or "").strip().lower()
        if text and text not in result:
            result.append(text)
    return result


def _normalized_text(value: Any) -> str:
    return re.sub(r"\s+", " ", str(value or "")).strip()


def _split_text(text: str, chunk_chars: int, overlap_chars: int) -> list[str]:
    text = _normalized_text(text)
    if not text:
        return []

    chunk_chars = max(50, int(chunk_chars))
    overlap_chars = max(0, min(int(overlap_chars), chunk_chars // 2))
    chunks: list[str] = []
    start = 0
    text_length = len(text)
    while start < text_length:
        proposed_end = min(text_length, start + chunk_chars)
        end = proposed_end
        if proposed_end < text_length:
            # Prefer a word boundary in the second half of the window.  If no
            # boundary exists (for example, a long identifier), use the exact
            # character limit so the loop always makes progress.
            boundary = text.rfind(" ", start + chunk_chars // 2, proposed_end)
            if boundary > start:
                end = boundary

        chunk = text[start:end].strip()
        if chunk:
            chunks.append(chunk)
        if end >= text_length:
            break
        next_start = end - overlap_chars
        start = next_start if next_start > start else end
    return chunks


def _page_number(value: Any) -> int | None:
    try:
        page = int(value)
    except Exception:
        return None
    return page if page > 0 else None


def _latest_document_records(documents: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], list[dict[str, Any]], int]:
    """Select the latest active version per document and return delete plans."""
    grouped: dict[str, list[dict[str, Any]]] = {}
    invalid_count = 0
    for document in documents:
        if not isinstance(document, dict):
            invalid_count += 1
            continue
        document_id = str(document.get("document_id") or "").strip()
        if not document_id:
            invalid_count += 1
            continue
        grouped.setdefault(document_id, []).append(document)

    selected: list[dict[str, Any]] = []
    delete_operations: list[dict[str, Any]] = []
    for document_id, records in grouped.items():
        latest_version = max((str(record.get("version") or "1") for record in records), key=_version_key)
        latest_records = [record for record in records if str(record.get("version") or "1") == latest_version]

        has_tombstone = any(
            _as_bool(record.get("deleted"), False) or not _as_bool(record.get("active"), True)
            for record in latest_records
        )
        if has_tombstone:
            reason = "tombstone" if any(_as_bool(record.get("deleted"), False) for record in latest_records) else "inactive"
            delete_operations.append(
                {
                    "operation": "delete_document",
                    "document_id": document_id,
                    "version": latest_version,
                    "reason": reason,
                }
            )
            continue

        selected.extend(latest_records)
    return selected, delete_operations, invalid_count


def _all_active_records(documents: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], list[dict[str, Any]], int]:
    active: list[dict[str, Any]] = []
    delete_operations: list[dict[str, Any]] = []
    invalid_count = 0
    for document in documents:
        if not isinstance(document, dict):
            invalid_count += 1
            continue
        document_id = str(document.get("document_id") or "").strip()
        if not document_id:
            invalid_count += 1
            continue
        version = str(document.get("version") or "1")
        if _as_bool(document.get("deleted"), False) or not _as_bool(document.get("active"), True):
            delete_operations.append(
                {
                    "operation": "delete_document_version",
                    "document_id": document_id,
                    "version": version,
                    "reason": "tombstone" if _as_bool(document.get("deleted"), False) else "inactive",
                }
            )
        else:
            active.append(document)
    return active, delete_operations, invalid_count


def _chunk_record(document: dict[str, Any], chunk: str, chunk_index: int) -> dict[str, Any]:
    document_id = str(document.get("document_id") or "").strip()
    version = str(document.get("version") or "1").strip()
    page = _page_number(document.get("page"))
    locator = str(document.get("source_locator") or "").strip()
    if not locator:
        locator = f"page:{page}" if page is not None else f"document:{document_id}"

    chunk_content_hash = hashlib.sha256(chunk.encode("utf-8")).hexdigest()
    identity = "|".join([document_id, version, locator, str(chunk_index), chunk_content_hash])
    chunk_id = hashlib.sha256(identity.encode("utf-8")).hexdigest()
    metadata = {
        "document_id": document_id,
        "title": str(document.get("title") or document_id).strip(),
        "version": version,
        "page": page,
        "source_locator": locator,
        "source_url": str(document.get("source_url") or "").strip(),
        "source_name": str(document.get("source_name") or "").strip(),
        "source_file": str(document.get("source_name") or "").strip(),
        "tenant_id": str(document.get("tenant_id") or "").strip().lower(),
        "visibility": str(document.get("visibility") or document.get("classification") or "internal").strip().lower(),
        "classification": str(document.get("classification") or "internal").strip().lower(),
        "allowed_roles": _string_list(document.get("allowed_roles")),
        "allowed_groups": _string_list(document.get("allowed_groups")),
        "chunk_index": chunk_index,
        "chunk_content_hash": chunk_content_hash,
    }
    return {
        "id": chunk_id,
        "chunk_id": chunk_id,
        "text": chunk,
        "page_content": chunk,
        "metadata": metadata,
    }


def build_document_chunk_index(
    value: Any,
    *,
    chunk_chars: int = 900,
    overlap_chars: int = 120,
    max_chunks: int = 5_000,
    latest_version_only: bool = True,
) -> dict[str, Any]:
    """Build a deterministic, payload-local retrieval index.

    This component deliberately does not claim persistent vector-store writes.
    `operations` describes how a later persistent indexer should replace or
    delete versions, while `chunks` is immediately usable by the model-free
    lexical retriever in the example flow.
    """
    payload = _payload_from_value(value)
    raw_documents = payload.get("documents")
    documents = raw_documents if isinstance(raw_documents, list) else []
    chunk_chars = _clamp_int(chunk_chars, 900, 50, 20_000)
    overlap_chars = _clamp_int(overlap_chars, 120, 0, chunk_chars // 2)
    max_chunks = _clamp_int(max_chunks, 5_000, 1, 50_000)
    select_latest = _as_bool(latest_version_only, True)

    errors: list[str] = []
    warnings: list[str] = []
    if select_latest:
        selected_documents, delete_operations, invalid_document_count = _latest_document_records(documents)
    else:
        selected_documents, delete_operations, invalid_document_count = _all_active_records(documents)

    chunks_by_id: dict[str, dict[str, Any]] = {}
    source_chunk_count = 0
    limit_reached = False
    for document in selected_documents:
        content = str(document.get("content") or "").strip()
        if not content:
            invalid_document_count += 1
            continue
        for chunk_index, chunk in enumerate(_split_text(content, chunk_chars, overlap_chars), start=1):
            source_chunk_count += 1
            record = _chunk_record(document, chunk, chunk_index)
            chunks_by_id.setdefault(record["id"], record)
            if len(chunks_by_id) >= max_chunks:
                limit_reached = True
                break
        if limit_reached:
            break

    chunks = list(chunks_by_id.values())
    deduplicated_chunk_count = max(0, source_chunk_count - len(chunks))

    chunk_ids_by_document: dict[tuple[str, str], list[str]] = {}
    for chunk in chunks:
        metadata = chunk["metadata"]
        key = (metadata["document_id"], metadata["version"])
        chunk_ids_by_document.setdefault(key, []).append(chunk["id"])

    upsert_operations: list[dict[str, Any]] = []
    for (document_id, version), chunk_ids in sorted(chunk_ids_by_document.items()):
        upsert_operations.append(
            {
                "operation": "replace_document_version" if select_latest else "upsert_document_version",
                "document_id": document_id,
                "version": version,
                "delete_previous_versions": select_latest,
                "upsert_chunk_ids": chunk_ids,
            }
        )
    operations = delete_operations + upsert_operations

    if not documents:
        errors.append("No documents were available for chunk indexing.")
    if invalid_document_count:
        warnings.append("One or more document records were skipped because required indexing fields were missing.")
    if deduplicated_chunk_count:
        warnings.append("Duplicate chunks were removed by their stable chunk IDs.")
    if limit_reached:
        warnings.append("The maximum chunk limit was reached; remaining content was not indexed.")
    if documents and not chunks and delete_operations:
        warnings.append("The current payload contains deletion or inactive records and no active chunks.")
    if documents and not chunks and not delete_operations:
        errors.append("No active text chunks could be built from the document payload.")

    # Deletion-only payloads are valid ingestion plans. They are intentionally
    # successful even though the model-free current-run index is empty.
    success = bool(chunks or delete_operations) and not errors
    selected_document_ids = sorted({chunk["metadata"]["document_id"] for chunk in chunks})
    selected_versions = {
        document_id: sorted(
            {chunk["metadata"]["version"] for chunk in chunks if chunk["metadata"]["document_id"] == document_id},
            key=_version_key,
        )[-1]
        for document_id in selected_document_ids
    }

    return {
        "success": success,
        "stage": "document_chunk_index_builder",
        "backend": "payload_lexical_v1",
        "persistence": "ephemeral_current_run",
        "chunks": chunks,
        "chunk_count": len(chunks),
        "document_count": len(selected_document_ids),
        "selected_versions": selected_versions,
        "operations": operations,
        "operation_count": len(operations),
        "delete_operation_count": len(delete_operations),
        "deduplicated_chunk_count": deduplicated_chunk_count,
        "settings": {
            "chunk_chars": chunk_chars,
            "overlap_chars": overlap_chars,
            "max_chunks": max_chunks,
            "latest_version_only": select_latest,
        },
        "errors": errors,
        "warnings": warnings,
        "trace": [
            {
                "stage": "document_chunk_index_builder",
                "status": "success" if success else "failed",
                "backend": "payload_lexical_v1",
                "input_document_count": len(documents),
                "indexed_document_count": len(selected_document_ids),
                "chunk_count": len(chunks),
                "delete_operation_count": len(delete_operations),
                "deduplicated_chunk_count": deduplicated_chunk_count,
                "limit_reached": limit_reached,
            }
        ],
    }


class DocumentChunkIndexBuilder(Component):
    display_name = "02 Document Chunk Index Builder"
    description = "Build stable, deduplicated chunks and version/tombstone operations for a model-free payload index."
    icon = "DatabaseZap"
