    lines.extend(
        [
            "",
            "경비 요청에는 expense_precheck_skill, 휴가 기간 요청에는 leave_policy_skill, ",
            "회의 담당자·할 일·기한 정리에는 meeting_action_skill을 사용하십시오.",
            "이 데모 결과는 실제 결재·인사·메일·캘린더 시스템에 반영되지 않습니다.",
        ]
    )
    return "\n".join(lines)


