                "recommended_when": ["추천 조건"],
                "not_recommended_when": ["비추천 조건"],
                "langflow_building_blocks": ["Langflow 구성 요소"],
                "risk_level": "low | medium | high",
                "human_review_required": False,
                "source_links": ["https://..."],
            }
        ]
    }


def _payload(value: Any) -> dict[str, Any]:
